def calculate_average_effectiveness(feedback, treatment_name):
    # Initialize a list to store the effectiveness ratings for the specified treatment
    treatment_ratings = []

    # Iterate through each patient's feedback
    for patient in feedback:
        if treatment_name in patient["treatments"]:
            treatment_ratings.append(patient["treatments"][treatment_name])

    # Calculate the average effectiveness
    if treatment_ratings:
        average = sum(treatment_ratings) / len(treatment_ratings)
        return round(average, 2)
    else:
        return 0.0

